mapper.select:
SELECT id, rule_type, rule_value, scope, action_type, category, reason, memo, active, waf_sync_enabled, waf_sync_status, waf_rule_id, last_synced_at, expires_at, created_by, updated_by, created_at, updated_at FROM admin_security_block_rule WHERE 1 = 1
AND ( rule_value LIKE CONCAT('%', #{keyword}, '%') OR reason LIKE CONCAT('%', #{keyword}, '%') OR memo LIKE CONCAT('%', #{keyword}, '%') OR waf_rule_id LIKE CONCAT('%', #{keyword}, '%') )
AND rule_type = #{ruleType}
AND active = #{active}
ORDER BY active DESC, updated_at DESC, id DESC LIMIT #{limit}

mapper.insert:
INSERT INTO admin_security_block_rule (
    rule_type, rule_value, scope, action_type, category, reason, memo,
    active, waf_sync_enabled, waf_sync_status, expires_at, created_by, updated_by
)
VALUES (
    #{ruleType}, #{ruleValue}, #{scope}, #{actionType}, #{category}, #{reason}, #{memo},
    #{active}, #{wafSyncEnabled}, #{wafSyncStatus}, #{expiresAt}, #{actorId}, #{actorId}
)

mapper.update:
UPDATE admin_security_block_rule
SET waf_sync_status = #{status},
    waf_rule_id = COALESCE(#{wafRuleId}, waf_rule_id),
    last_synced_at = #{lastSyncedAt},
    updated_by = #{actorId}
WHERE id = #{id}

