SELECT id, block_rule_id, provider_code, operation_type, status, JSON_UNQUOTE(JSON_EXTRACT(request_payload_json, '$')) AS request_payload_json, JSON_UNQUOTE(JSON_EXTRACT(response_payload_json, '$')) AS response_payload_json, error_message, requested_by, requested_at, processed_at FROM admin_security_waf_sync_event WHERE 1 = 1
AND ( provider_code LIKE CONCAT('%', #{keyword}, '%') OR operation_type LIKE CONCAT('%', #{keyword}, '%') OR error_message LIKE CONCAT('%', #{keyword}, '%') )
AND status = #{status}
ORDER BY requested_at DESC, id DESC LIMIT #{limit}

