mapper.select:
SELECT h.id, h.provider_config_id, h.provider_code, h.provider_type, h.check_source, h.status_before, h.status_after, h.detail_message, h.actor_user_id, u.email AS actor_email, h.checked_at FROM admin_security_provider_health_history h LEFT JOIN users u ON u.id = h.actor_user_id WHERE 1 = 1
AND ( h.provider_code LIKE CONCAT('%', #{keyword}, '%') OR h.provider_type LIKE CONCAT('%', #{keyword}, '%') OR h.check_source LIKE CONCAT('%', #{keyword}, '%') OR h.detail_message LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') )
AND h.status_after = #{statusAfter}
ORDER BY h.checked_at DESC, h.id DESC LIMIT #{limit}

SELECT id, review_type, subject_type, subject_value, risk_score, risk_level, status, decision_action, reason, JSON_UNQUOTE(JSON_EXTRACT(evidence_json, '$')) AS evidence_json, created_by, assigned_to, decided_by, decided_at, created_at, updated_at FROM admin_security_review WHERE 1 = 1
AND ( subject_value LIKE CONCAT('%', #{keyword}, '%') OR reason LIKE CONCAT('%', #{keyword}, '%') OR decision_action LIKE CONCAT('%', #{keyword}, '%') )
AND status = #{status}
AND review_type = #{reviewType}
ORDER BY FIELD(risk_level, 'CRITICAL', 'HIGH', 'MEDIUM', 'LOW'), created_at DESC, id DESC LIMIT #{limit}

mapper.insert:
INSERT INTO admin_security_review (
    review_type, subject_type, subject_value, risk_score, risk_level, status,
    decision_action, reason, evidence_json, assigned_to, created_by
)
VALUES (
    #{reviewType}, #{subjectType}, #{subjectValue}, #{riskScore}, #{riskLevel}, #{status},
    #{decisionAction}, #{reason}, CAST(#{evidenceJson} AS JSON), #{assignedTo}, #{actorId}
)

