SELECT id, public_request_id, subject_type, subject_value, block_rule_id, submitter_email, status, reason, decision_reason, reviewed_by, reviewed_at, created_at, updated_at FROM admin_security_appeal WHERE 1 = 1
AND ( public_request_id LIKE CONCAT('%', #{keyword}, '%') OR subject_value LIKE CONCAT('%', #{keyword}, '%') OR submitter_email LIKE CONCAT('%', #{keyword}, '%') OR reason LIKE CONCAT('%', #{keyword}, '%') )
AND status = #{status}
ORDER BY created_at DESC, id DESC LIMIT #{limit}

mapper.update:
UPDATE admin_security_appeal
SET status = #{status},
    decision_reason = #{decisionReason},
    reviewed_by = #{actorId},
    reviewed_at = #{reviewedAt}
WHERE id = #{id}
